#include<bits/stdc++.h>
using namespace std;
long long phi(long long n)
{
    long long ans=n;
    for(long long i=2;i*i<=n;i++)
    {
        if(n%i==0)
        {
            ans=ans/i*(i-1);
            while(n%i==0)
            {
                n/=i;
            }
        }
    }
    if(n>1)
    {
        ans=ans/n*(n-1);
    }
    return ans;
}
int main()
{
    long long n;
    scanf("%lld",&n);
    if(n==1)
    {
        printf("1");
        return 0;
    }
    long long ans=0;
    for(long long i=1;1ll*i*i<=n;i++)
    {
        if(n%i==0)
        {
            ans+=1ll*i*phi(n/i);
            if(i!=n/i)
            {
                ans+=1ll*(n/i)*phi(i);
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
